allow:
Bash(/opt/homebrew/opt/postgresql@16/bin/psql -U $USER postgres -c "
  DO \\$\\$
  BEGIN
    IF NOT EXISTS \(SELECT FROM pg_catalog.pg_roles WHERE rolname = 'postgres'\) THEN
      CREATE ROLE postgres WITH LOGIN PASSWORD 'postgres' SUPERUSER;
    END IF;
  END
  \\$\\$;
  CREATE DATABASE pm_platform OWNER postgres;
  CREATE DATABASE pm_platform_test OWNER postgres;
" 2>&1)
